export enum ChineseStyle {
  NEW_CHINESE = 'New Chinese (Modern)',
  CLASSICAL = 'Classical Chinese',
  ZEN_MINIMALISM = 'Zen Minimalism',
  LUXURY_ORIENTAL = 'Luxury Oriental'
}

export interface DesignConfig {
  style: ChineseStyle;
  roomType: string;
  intensity: number;
}

export interface TransformationResult {
  originalUrl: string;
  resultUrl: string;
  timestamp: number;
}

import React from 'react';
import { ChineseStyle } from './types';

export const CHINESE_STYLES = [
  {
    id: ChineseStyle.NEW_CHINESE,
    name: '新中式 (New Chinese)',
    description: 'A blend of modern comfort with traditional aesthetic lines and materials.',
    preview: 'https://images.unsplash.com/photo-1615873968403-89e068629275?auto=format&fit=crop&q=80&w=400'
