    preview: 'https://images.unsplash.com/photo-1616486332353-47e947c0ef5e?auto=format&fit=crop&q=80&w=400'
  },
  {
    id: ChineseStyle.ZEN_MINIMALISM,
    name: '禅意简约 (Zen)',
