export const ROOM_TYPES = [
  'Living Room (客厅)',
  'Bedroom (卧室)',
  'Dining Room (餐厅)',
  'Study (书房)',
  'Tea Room (茶室)'
];

import { GoogleGenAI } from "@google/genai";
import { ChineseStyle } from "../types";

export async function transformRoomImage(
  base64Image: string,
  style: ChineseStyle,
  roomType: string
): Promise<string> {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const stylePrompts: Record<ChineseStyle, string> = {
    [ChineseStyle.NEW_CHINESE]: "Modern Chinese style with clean lines, dark wood accents, neutral tones, and elegant furniture. Blend traditional lattice patterns with contemporary sofa designs.",
    [ChineseStyle.CLASSICAL]: "Rich classical Chinese interior. Heavy use of dark rosewood (Hongmu), intricate lattice screens, traditional ink wash paintings on walls, silk fabrics, and symmetrical furniture arrangements.",
    [ChineseStyle.ZEN_MINIMALISM]: "Zen-inspired Chinese minimalism. Light wood, bamboo, stone textures, low-profile furniture, plenty of negative space, and a bonsai or small tea set as accents.",
    [ChineseStyle.LUXURY_ORIENTAL]: "High-end luxury Oriental design. Marble floors with traditional patterns, gold leaf accents, massive wooden ceiling beams, and expensive traditional art pieces."
  };

  const systemInstruction = `You are a world-class Chinese interior designer. 
  Your task is to take a photo of a raw shell house (unfinished room) and overlay a high-quality interior design.
  CRITICAL RULE: DO NOT change the structural bones of the house. Keep all walls, columns, windows, and structural beams in their exact positions.
  Task: Overlay ${stylePrompts[style]} onto this ${roomType}.
  Details: Add flooring, wall finishes, ceiling decorations, lighting fixtures, and high-end furniture that fits the ${style} aesthetic. 
  The final result must look like a real professional architectural visualization.`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: {
        parts: [
          {
            inlineData: {
              data: base64Image.split(',')[1] || base64Image,
              mimeType: 'image/jpeg',
            },
          },
          {
            text: `Please transform this raw shell house into a fully decorated ${style} ${roomType}. Remember to strictly preserve the existing structural architecture of the space.`,
          },
        ],
      },
      config: {
        imageConfig: {
          aspectRatio: "4:3"
        }
      }
    });

    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData) {
        return `data:image/png;base64,${part.inlineData.data}`;
      }
    }

    throw new Error("No image was generated by the model.");
  } catch (error) {
    console.error("Gemini API Error:", error);
    throw error;
  }
}

