import React, { useState, useRef, useEffect } from 'react';

interface ComparisonSliderProps {
  beforeUrl: string;
  afterUrl: string;
}

const ComparisonSlider: React.FC<ComparisonSliderProps> = ({ beforeUrl, afterUrl }) => {
  const [position, setPosition] = useState(50);
  const containerRef = useRef<HTMLDivElement>(null);

  const handleMove = (e: React.MouseEvent | React.TouchEvent) => {
    if (!containerRef.current) return;
    const rect = containerRef.current.getBoundingClientRect();
    const x = 'touches' in e ? e.touches[0].clientX : e.clientX;
    const relativeX = x - rect.left;
    const newPosition = Math.max(0, Math.min(100, (relativeX / rect.width) * 100));
    setPosition(newPosition);
  };

  return (
    <div 
      ref={containerRef}
      className="relative w-full aspect-[4/3] rounded-xl overflow-hidden cursor-ew-resize group shadow-2xl bg-stone-100"
      onMouseMove={handleMove}
      onTouchMove={handleMove}
    >
      {/* After Image */}
      <img 
        src={afterUrl} 
        alt="After" 
        className="absolute inset-0 w-full h-full object-cover"
      />

      {/* Before Image (Clipped) */}
      <div 
        className="absolute inset-0 w-full h-full overflow-hidden"
        style={{ width: `${position}%` }}
      >
        <img 
          src={beforeUrl} 
          alt="Before" 
          className="absolute inset-0 w-[100vw] h-full object-cover max-w-none"
          style={{ width: containerRef.current?.offsetWidth }}
        />
        <div className="absolute top-4 left-4 bg-black/50 text-white px-2 py-1 text-xs rounded uppercase tracking-widest font-bold">
          Before (毛坯房)
        </div>
      </div>

      {/* After Label */}
      <div className="absolute top-4 right-4 bg-stone-900/50 text-white px-2 py-1 text-xs rounded uppercase tracking-widest font-bold">
        After (装修效果)
      </div>

      {/* Slider Handle */}
      <div 
        className="absolute top-0 bottom-0 w-1 bg-white shadow-lg pointer-events-none"
        style={{ left: `${position}%` }}
      >
        <div className="absolute top-1/2 -translate-y-1/2 -translate-x-1/2 w-10 h-10 bg-white rounded-full shadow-xl flex items-center justify-center border-2 border-stone-200">
          <div className="flex gap-1">
            <div className="w-1.5 h-1.5 bg-stone-400 rounded-full"></div>
            <div className="w-1.5 h-1.5 bg-stone-400 rounded-full"></div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default ComparisonSlider;

import React, { useState, useCallback } from 'react';
