        originalUrl: selectedImage,
        resultUrl,
        timestamp: Date.now()
      });
    } catch (err) {
      setError("Failed to transform image. Please try again with a clearer photo.");
      console.error(err);
    } finally {
      setIsProcessing(false);
    }
