              <select 
                value={selectedRoom}
                onChange={(e) => setSelectedRoom(e.target.value)}
                className="w-full bg-stone-50 border border-stone-200 rounded-lg px-4 py-2 text-stone-700 focus:outline-none focus:ring-2 focus:ring-stone-900 transition-all"
              >
                {ROOM_TYPES.map(room => (
