                <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><circle cx="12" cy="12" r="10"/><line x1="12" x2="12" y1="8" y2="12"/><line x1="12" x2="12.01" y1="16" y2="16"/></svg>
                <p className="text-sm font-medium">{error}</p>
              </div>
            )}

            {/* Feature Cards */}
            <div className="grid grid-cols-1 md:grid-cols-3 gap-6 pt-8">
              <div className="bg-stone-50 p-6 rounded-2xl border border-stone-200">
                <div className="w-10 h-10 bg-stone-900 text-white rounded-lg flex items-center justify-center mb-4">
                  <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M12 22s8-4 8-10V5l-8-3-8 3v7c0 6 8 10 8 10"/></svg>
                </div>
                <h4 className="font-bold text-stone-900 mb-2">Preserve Structure</h4>
                <p className="text-stone-600 text-sm leading-relaxed">Our AI recognizes walls and pillars, ensuring designs fit your actual space constraints perfectly.</p>
              </div>
              <div className="bg-stone-50 p-6 rounded-2xl border border-stone-200">
                <div className="w-10 h-10 bg-stone-900 text-white rounded-lg flex items-center justify-center mb-4">
                  <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><circle cx="12" cy="12" r="10"/><path d="m16 10-4 4-4-4"/></svg>
                </div>
                <h4 className="font-bold text-stone-900 mb-2">Chinese Aesthetics</h4>
                <p className="text-stone-600 text-sm leading-relaxed">Expertly curated traditional styles, from classical rosewood to contemporary Zen minimalism.</p>
              </div>
              <div className="bg-stone-50 p-6 rounded-2xl border border-stone-200">
                <div className="w-10 h-10 bg-stone-900 text-white rounded-lg flex items-center justify-center mb-4">
                  <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="m12 3-1.912 5.813a2 2 0 0 1-1.275 1.275L3 12l5.813 1.912a2 2 0 0 1 1.275 1.275L12 21l1.912-5.813a2 2 0 0 1 1.275-1.275L21 12l-5.813-1.912a2 2 0 0 1-1.275-1.275L12 3Z"/></svg>
                </div>
                <h4 className="font-bold text-stone-900 mb-2">Instant Visualization</h4>
                <p className="text-stone-600 text-sm leading-relaxed">See your future home in seconds. Perfect for early-stage planning and inspiration.</p>
              </div>
            </div>
          </div>

        </div>
      </main>

      <footer className="bg-white border-t border-stone-200 py-12">
        <div className="max-w-7xl mx-auto px-4 text-center">
          <div className="flex justify-center items-center gap-2 mb-4">
            <div className="w-6 h-6 bg-stone-800 flex items-center justify-center rounded-sm">
              <span className="text-white font-serif-sc text-sm">禅</span>
            </div>
            <span className="text-lg font-serif-sc font-bold tracking-tight">ZenDecor AI</span>
          </div>
          <p className="text-stone-500 text-sm">© 2024 ZenDecor. Powered by Gemini. All structural data preserved.</p>
        </div>
      </footer>
    </div>
  );
};

export default App;

