import { GoogleGenAI } from "@google/genai";
import { ChineseStyle } from "../types";

export async function transformRoomImage(
  base64Image: string,
  style: ChineseStyle,
  roomType: string
): Promise<string> {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const stylePrompts: Record<ChineseStyle, string> = {
    [ChineseStyle.NEW_CHINESE]: "Modern Chinese style with clean lines, dark wood accents, neutral tones, and elegant furniture. Blend traditional lattice patterns with contemporary sofa designs.",
    [ChineseStyle.CLASSICAL]: "Rich classical Chinese interior. Heavy use of dark rosewood (Hongmu), intricate lattice screens, traditional ink wash paintings on walls, silk fabrics, and symmetrical furniture arrangements.",
    [ChineseStyle.ZEN_MINIMALISM]: "Zen-inspired Chinese minimalism. Light wood, bamboo, stone textures, low-profile furniture, plenty of negative space, and a bonsai or small tea set as accents.",
    [ChineseStyle.LUXURY_ORIENTAL]: "High-end luxury Oriental design. Marble floors with traditional patterns, gold leaf accents, massive wooden ceiling beams, and expensive traditional art pieces."
  };

  const systemInstruction = `You are a world-class Chinese interior designer specializing in architectural visualization. 
  Your mission is to take a photo of a raw shell house (unfinished room with exposed concrete/brick) and provide a completed interior decoration.

  STRICT ARCHITECTURAL CONSTRAINTS:
  1. EXACT PIXEL ALIGNMENT: You MUST preserve the exact structural bones of the original image. Every wall, column, window frame, and structural beam must stay in its precise original location and orientation. Do not move or distort the architecture.
  2. 100% SURFACE COVERAGE: No raw concrete, brick, or construction markings should be visible. Cover all exposed structural elements with finished materials: 
     - Walls: Smooth paint, elegant wallpaper, or wood paneling.
     - Floors: High-quality stone, polished wood, or traditional tiles.
     - Ceiling: Integrated decorative ceilings with modern lighting.
  3. NO WATERMARKS: The final image must be clean and professional. Do not add any text, logos, stamps, or watermarks.

  STYLE SPECIFICATION:
  Apply ${stylePrompts[style]} to this ${roomType}. 
  Ensure realistic lighting that respects the window placements of the original photo.`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: {
        parts: [
          {
            inlineData: {
              data: base64Image.split(',')[1] || base64Image,
              mimeType: 'image/jpeg',
            },
          },
          {
            text: `Strictly maintain the architecture of this shell house while applying a full ${style} decoration for a ${roomType}. Ensure all raw surfaces are covered and no watermarks are present.`,
          },
        ],
      },
      config: {
        imageConfig: {
          aspectRatio: "4:3"
        }
      }
    });

    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData) {
        return `data:image/png;base64,${part.inlineData.data}`;
      }
    }

    throw new Error("No image was generated by the model.");
  } catch (error) {
    console.error("Gemini API Error:", error);
    throw error;
  }
}

import React, { useState, useRef, useEffect } from 'react';

interface ComparisonSliderProps {
  beforeUrl: string;
  afterUrl: string;
}

const ComparisonSlider: React.FC<ComparisonSliderProps> = ({ beforeUrl, afterUrl }) => {
  const [position, setPosition] = useState(50);
  const [isDragging, setIsDragging] = useState(false);
  const containerRef = useRef<HTMLDivElement>(null);

  const handleMove = (e: MouseEvent | TouchEvent) => {
    if (!isDragging || !containerRef.current) return;

    const rect = containerRef.current.getBoundingClientRect();
    const x = 'touches' in e ? e.touches[0].clientX : (e as MouseEvent).clientX;
    const relativeX = x - rect.left;
    const newPosition = Math.max(0, Math.min(100, (relativeX / rect.width) * 100));
    setPosition(newPosition);
  };

  const handleStart = (e: React.MouseEvent | React.TouchEvent) => {
    // Only allow left-click drag
    if ('button' in e && e.button !== 0) return;
    setIsDragging(true);
  };

  const handleEnd = () => setIsDragging(false);

  useEffect(() => {
    if (isDragging) {
      window.addEventListener('mousemove', handleMove);
      window.addEventListener('mouseup', handleEnd);
      window.addEventListener('touchmove', handleMove);
      window.addEventListener('touchend', handleEnd);
    } else {
      window.removeEventListener('mousemove', handleMove);
      window.removeEventListener('mouseup', handleEnd);
      window.removeEventListener('touchmove', handleMove);
      window.removeEventListener('touchend', handleEnd);
    }
    return () => {
      window.removeEventListener('mousemove', handleMove);
      window.removeEventListener('mouseup', handleEnd);
      window.removeEventListener('touchmove', handleMove);
      window.removeEventListener('touchend', handleEnd);
    };
  }, [isDragging]);

  return (
    <div 
      ref={containerRef}
      className="relative w-full aspect-[4/3] rounded-xl overflow-hidden cursor-ew-resize group shadow-2xl bg-stone-100 select-none border border-stone-200"
      onMouseDown={handleStart}
      onTouchStart={handleStart}
    >
      {/* After Image */}
      <img 
        src={afterUrl} 
        alt="After" 
        className="absolute inset-0 w-full h-full object-cover pointer-events-none"
      />

      {/* Before Image (Clipped) */}
      <div 
        className="absolute inset-0 w-full h-full overflow-hidden pointer-events-none z-10"
        style={{ width: `${position}%` }}
      >
        <img 
          src={beforeUrl} 
          alt="Before" 
          className="absolute inset-0 w-[100vw] h-full object-cover max-w-none"
          style={{ width: containerRef.current?.offsetWidth }}
        />
        <div className="absolute top-4 left-4 bg-black/60 text-white px-3 py-1.5 text-xs rounded-full uppercase tracking-widest font-bold backdrop-blur-sm">
          Before (毛坯房)
        </div>
      </div>

      {/* After Label */}
      <div className="absolute top-4 right-4 bg-stone-900/60 text-white px-3 py-1.5 text-xs rounded-full uppercase tracking-widest font-bold pointer-events-none backdrop-blur-sm z-20">
        After (装修效果)
      </div>

      {/* Slider Handle */}
      <div 
        className={`absolute top-0 bottom-0 w-0.5 bg-white/80 shadow-[0_0_15px_rgba(0,0,0,0.3)] z-30 pointer-events-none`}
        style={{ left: `${position}%` }}
      >
        <div className={`absolute top-1/2 -translate-y-1/2 -translate-x-1/2 w-12 h-12 bg-white rounded-full shadow-2xl flex items-center justify-center border-4 border-white/50 transition-transform ${isDragging ? 'scale-110' : 'group-hover:scale-105'}`}>
          <div className="flex gap-1.5">
            <div className={`w-1 h-4 bg-stone-400 rounded-full transition-colors ${isDragging ? 'bg-stone-900' : ''}`}></div>
            <div className={`w-1 h-4 bg-stone-400 rounded-full transition-colors ${isDragging ? 'bg-stone-900' : ''}`}></div>
          </div>
        </div>
      </div>

      {/* Visual Cue for interaction */}
      {!isDragging && (
        <div className="absolute inset-x-0 bottom-12 flex justify-center pointer-events-none z-40">
          <div className="bg-black/40 backdrop-blur-md text-white px-4 py-2 rounded-full text-xs font-medium animate-bounce border border-white/20">
            按住左键拖动对比 (Click & Drag to Compare)
          </div>
        </div>
      )}
    </div>
  );
};

