import { GoogleGenAI } from "@google/genai";
import { ChineseStyle } from "../types";

export async function transformRoomImage(
  base64Image: string,
  style: ChineseStyle,
  roomType: string
): Promise<string> {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const stylePrompts: Record<ChineseStyle, string> = {
    [ChineseStyle.NEW_CHINESE]: "Modern Chinese style, clean lines, neutral colors, dark wood accents, elegant furniture, balanced composition.",
    [ChineseStyle.CLASSICAL]: "Classical Chinese, rosewood furniture, intricate lattice screens, silk textures, symmetrical layout, traditional art.",
    [ChineseStyle.ZEN_MINIMALISM]: "Zen style, bamboo, stone, light wood, simple furniture, peaceful atmosphere, natural lighting.",
    [ChineseStyle.LUXURY_ORIENTAL]: "Grand Oriental luxury, marble flooring, high ceilings, gold accents, premium wooden beams, expensive textures."
  };

  const systemInstruction = `你是一位世界顶级的室内设计专家，擅长将毛坯房转换为中式装修风格。

  核心执行规则：
  1. 结构保护：必须严格保留原图中的所有建筑结构。墙体、立柱、梁位、门窗框的位置和透视关系严禁改动。
  2. 表面全覆盖：原图中所有的水泥、红砖、粗糙毛坯表面必须全部覆盖上装修材料（乳胶漆、壁纸、木饰面、大理石或高档瓷砖）。不准漏出任何毛坯痕迹。
  3. 真实光影：根据原图窗户位置模拟自然光，安装中式灯具。
  4. 无水印：生成结果必须保持纯净，严禁出现任何文字、水印、标志。

  设计要求：在保持建筑结构的前提下，将这个${roomType}装修为${style}风格。`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: {
        parts: [
          {
            inlineData: {
              data: base64Image.split(',')[1] || base64Image,
              mimeType: 'image/jpeg',
            },
          },
          {
            text: `请将这张毛坯房照片在原图基础上进行${style}装修美化。严禁改动任何墙体和结构，确保所有毛坯表面都被覆盖。最终图像不得有水印。`,
          },
        ],
      },
      config: {
        imageConfig: {
          aspectRatio: "4:3"
        }
      }
    });

    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData) {
        return `data:image/png;base64,${part.inlineData.data}`;
      }
    }

    throw new Error("模型未生成图像，请重试。");
  } catch (error) {
    console.error("Gemini API Error:", error);
    throw error;
  }
}

