import React, { useState, useRef, useEffect } from 'react';

interface ComparisonSliderProps {
  beforeUrl: string;
  afterUrl: string;
}

const ComparisonSlider: React.FC<ComparisonSliderProps> = ({ beforeUrl, afterUrl }) => {
  const [position, setPosition] = useState(50);
  const [isDragging, setIsDragging] = useState(false);
  const containerRef = useRef<HTMLDivElement>(null);

  const handleMove = (e: MouseEvent | TouchEvent) => {
    if (!isDragging || !containerRef.current) return;

    const rect = containerRef.current.getBoundingClientRect();
    const x = 'touches' in e ? e.touches[0].clientX : (e as MouseEvent).clientX;
    const relativeX = x - rect.left;
    const newPosition = Math.max(0, Math.min(100, (relativeX / rect.width) * 100));
    setPosition(newPosition);
  };

  const handleStart = (e: React.MouseEvent | React.TouchEvent) => {
    // 仅允许鼠标左键点击拖拽
    if ('button' in e && e.button !== 0) return;
    setIsDragging(true);
  };

  const handleEnd = () => setIsDragging(false);

  useEffect(() => {
    if (isDragging) {
      window.addEventListener('mousemove', handleMove);
      window.addEventListener('mouseup', handleEnd);
      window.addEventListener('touchmove', handleMove);
      window.addEventListener('touchend', handleEnd);
    } else {
      window.removeEventListener('mousemove', handleMove);
      window.removeEventListener('mouseup', handleEnd);
      window.removeEventListener('touchmove', handleMove);
      window.removeEventListener('touchend', handleEnd);
    }
    return () => {
      window.removeEventListener('mousemove', handleMove);
      window.removeEventListener('mouseup', handleEnd);
      window.removeEventListener('touchmove', handleMove);
      window.removeEventListener('touchend', handleEnd);
    };
  }, [isDragging]);

  return (
    <div 
      ref={containerRef}
      className="relative w-full aspect-[4/3] rounded-xl overflow-hidden cursor-ew-resize group shadow-2xl bg-stone-100 select-none border border-stone-200"
      onMouseDown={handleStart}
      onTouchStart={handleStart}
    >
      {/* 装修后图像 */}
      <img 
        src={afterUrl} 
        alt="装修后" 
        className="absolute inset-0 w-full h-full object-cover pointer-events-none"
      />

      {/* 装修前图像 (裁剪显示) */}
      <div 
        className="absolute inset-0 w-full h-full overflow-hidden pointer-events-none z-10"
        style={{ width: `${position}%` }}
      >
        <img 
          src={beforeUrl} 
          alt="毛坯房" 
          className="absolute inset-0 w-[100vw] h-full object-cover max-w-none"
          style={{ width: containerRef.current?.offsetWidth }}
        />
        <div className="absolute top-4 left-4 bg-black/60 text-white px-3 py-1.5 text-xs rounded-full uppercase tracking-widest font-bold backdrop-blur-sm">
          原图 (毛坯房)
        </div>
      </div>

      {/* 装修后标签 */}
      <div className="absolute top-4 right-4 bg-stone-900/60 text-white px-3 py-1.5 text-xs rounded-full uppercase tracking-widest font-bold pointer-events-none backdrop-blur-sm z-20">
        AI 装修效果
      </div>

      {/* 滑块手柄 */}
      <div 
        className={`absolute top-0 bottom-0 w-0.5 bg-white/80 shadow-[0_0_15px_rgba(0,0,0,0.3)] z-30 pointer-events-none`}
        style={{ left: `${position}%` }}
      >
        <div className={`absolute top-1/2 -translate-y-1/2 -translate-x-1/2 w-12 h-12 bg-white rounded-full shadow-2xl flex items-center justify-center border-4 border-white/50 transition-transform ${isDragging ? 'scale-110' : 'group-hover:scale-105'}`}>
          <div className="flex gap-1.5">
            <div className={`w-1 h-4 bg-stone-400 rounded-full transition-colors ${isDragging ? 'bg-stone-900' : ''}`}></div>
            <div className={`w-1 h-4 bg-stone-400 rounded-full transition-colors ${isDragging ? 'bg-stone-900' : ''}`}></div>
          </div>
        </div>
      </div>

      {/* 交互提示 */}
      {!isDragging && (
        <div className="absolute inset-x-0 bottom-12 flex justify-center pointer-events-none z-40">
          <div className="bg-black/40 backdrop-blur-md text-white px-4 py-2 rounded-full text-xs font-medium animate-bounce border border-white/20">
            按住左键拖动对比
          </div>
        </div>
      )}
    </div>
  );
};

export default ComparisonSlider;

import React, { useState } from 'react';
import Header from './components/Header';
import ComparisonSlider from './components/ComparisonSlider';
import { CHINESE_STYLES, ROOM_TYPES } from './constants';
import { ChineseStyle, TransformationResult } from './types';
import { transformRoomImage } from './services/geminiService';

const App: React.FC = () => {
  const [selectedImage, setSelectedImage] = useState<string | null>(null);
  const [selectedStyle, setSelectedStyle] = useState<ChineseStyle>(ChineseStyle.NEW_CHINESE);
  const [selectedRoom, setSelectedRoom] = useState<string>(ROOM_TYPES[0]);
  const [isProcessing, setIsProcessing] = useState(false);
  const [result, setResult] = useState<TransformationResult | null>(null);
  const [error, setError] = useState<string | null>(null);

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setSelectedImage(reader.result as string);
        setResult(null);
        setError(null);
      };
      reader.readAsDataURL(file);
    }
  };

  const handleGenerate = async () => {
    if (!selectedImage) return;

    setIsProcessing(true);
    setError(null);
    try {
      const resultUrl = await transformRoomImage(selectedImage, selectedStyle, selectedRoom);
      setResult({
        originalUrl: selectedImage,
        resultUrl,
        timestamp: Date.now()
      });
    } catch (err) {
      setError("图像转换失败。请尝试上传更清晰的照片，并确保光线充足。");
      console.error(err);
    } finally {
      setIsProcessing(false);
    }
  };

  const handleDownload = () => {
    if (!result) return;
    const link = document.createElement('a');
    link.href = result.resultUrl;
    link.download = `禅艺装修设计-${selectedStyle}-${selectedRoom}-${Date.now()}.png`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const reset = () => {
    setSelectedImage(null);
    setResult(null);
    setError(null);
  };

  return (
    <div className="min-h-screen flex flex-col">
      <Header />

      <main className="flex-grow max-w-7xl mx-auto px-4 py-8 sm:px-6 lg:px-8 w-full">
        <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">

          {/* 侧边控制栏 */}
          <div className="lg:col-span-4 space-y-8 order-2 lg:order-1">
            <section className="bg-white p-6 rounded-2xl shadow-sm border border-stone-100">
              <h2 className="text-lg font-bold text-stone-900 mb-6 font-serif-sc">1. 选择装修风格</h2>
              <div className="grid grid-cols-2 gap-3">
                {CHINESE_STYLES.map((style) => (
                  <button
                    key={style.id}
                    onClick={() => {
                      setSelectedStyle(style.id);
                      if (result) setResult(null);
                    }}
                    className={`relative rounded-xl overflow-hidden border-2 transition-all group ${
                      selectedStyle === style.id ? 'border-stone-900 ring-4 ring-stone-900/10' : 'border-transparent hover:border-stone-200'
                    }`}
                  >
                    <img src={style.preview} alt={style.name} className="w-full aspect-square object-cover" />
                    <div className="absolute inset-0 bg-gradient-to-t from-stone-900/80 via-transparent to-transparent flex items-end p-2">
                      <span className="text-[10px] sm:text-xs text-white font-medium">{style.name}</span>
                    </div>
                  </button>
                ))}
              </div>
            </section>

            <section className="bg-white p-6 rounded-2xl shadow-sm border border-stone-100">
              <h2 className="text-lg font-bold text-stone-900 mb-6 font-serif-sc">2. 空间类型</h2>
              <select 
                value={selectedRoom}
                onChange={(e) => {
                  setSelectedRoom(e.target.value);
                  if (result) setResult(null);
                }}
                className="w-full bg-stone-50 border border-stone-200 rounded-lg px-4 py-3 text-stone-700 focus:outline-none focus:ring-2 focus:ring-stone-900 transition-all font-medium"
              >
                {ROOM_TYPES.map(room => (
                  <option key={room} value={room}>{room}</option>
                ))}
              </select>
            </section>

            <button
              onClick={handleGenerate}
              disabled={!selectedImage || isProcessing}
              className={`w-full py-4 rounded-xl font-bold text-white transition-all shadow-lg flex items-center justify-center gap-2 ${
                !selectedImage || isProcessing 
                  ? 'bg-stone-300 cursor-not-allowed' 
                  : 'bg-stone-900 hover:bg-stone-800 hover:shadow-xl active:scale-95'
              }`}
            >
              {isProcessing ? (
                <>
                  <svg className="animate-spin h-5 w-5 text-white" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                    <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                    <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                  </svg>
                  智能设计中...
                </>
              ) : (
                <>生成装修方案</>
              )}
            </button>
          </div>

          {/* 主展示区 */}
          <div className="lg:col-span-8 space-y-6 order-1 lg:order-2">
            {!result ? (
              <div className="bg-white rounded-2xl shadow-sm border-2 border-dashed border-stone-200 aspect-[4/3] flex flex-col items-center justify-center p-8 transition-colors hover:border-stone-300 relative overflow-hidden group">
                {selectedImage ? (
                  <div className="w-full h-full relative">
                    <img src={selectedImage} alt="Preview" className="w-full h-full object-cover rounded-xl" />
                    <button 
                      onClick={reset}
                      className="absolute top-4 right-4 bg-white/90 backdrop-blur p-2 rounded-full shadow-lg hover:bg-white transition-colors text-stone-900"
                    >
                      <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M18 6 6 18"/><path d="m6 6 12 12"/></svg>
                    </button>
                    <div className="absolute inset-x-0 bottom-0 p-6 bg-gradient-to-t from-black/60 to-transparent">
                      <p className="text-white text-sm font-medium">原图实拍 (毛坯房)</p>
                    </div>
                  </div>
                ) : (
                  <>
                    <div className="w-20 h-20 bg-stone-100 rounded-full flex items-center justify-center mb-6 group-hover:scale-110 transition-transform">
                      <svg xmlns="http://www.w3.org/2000/svg" width="40" height="40" viewBox="0 0 24 24" fill="none" stroke="#78716c" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round"><rect width="18" height="18" x="3" y="3" rx="2" ry="2"/><circle cx="9" cy="9" r="2"/><path d="m21 15-3.086-3.086a2 2 0 0 0-2.828 0L6 21"/></svg>
                    </div>
                    <p className="text-stone-900 text-xl font-bold mb-2">上传您的毛坯房照片</p>
                    <p className="text-stone-500 text-sm mb-8 max-w-xs text-center">我们将在保持原始建筑结构的基础上，为您叠加全覆盖的精美装修方案。</p>
                    <input
                      type="file"
                      id="room-upload"
                      className="hidden"
                      accept="image/*"
                      onChange={handleImageUpload}
                    />
                    <label
                      htmlFor="room-upload"
                      className="bg-stone-900 text-white px-10 py-4 rounded-full font-bold hover:bg-stone-800 transition-colors cursor-pointer shadow-xl flex items-center gap-2"
                    >
                      <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4"/><polyline points="17 8 12 3 7 8"/><line x1="12" x2="12" y1="3" y2="15"/></svg>
                      选择照片
                    </label>
                  </>
                )}
              </div>
            ) : (
              <div className="space-y-6">
                <ComparisonSlider beforeUrl={result.originalUrl} afterUrl={result.resultUrl} />
                <div className="bg-white p-6 rounded-2xl shadow-sm border border-stone-100 flex flex-col sm:flex-row items-start sm:items-center justify-between gap-6">
                  <div>
                    <div className="flex items-center gap-2 mb-1">
                      <span className="bg-stone-900 text-white text-[10px] px-2 py-0.5 rounded font-bold uppercase tracking-wider">AI 智能设计</span>
                      <h3 className="font-bold text-stone-900 font-serif-sc text-lg">{selectedStyle} - {selectedRoom}</h3>
                    </div>
                    <p className="text-stone-500 text-sm italic">已严格保留原始建筑结构，并全面覆盖水泥表面。</p>
                  </div>
                  <div className="flex gap-4 w-full sm:w-auto">
                    <button 
                      onClick={handleDownload}
                      className="flex-1 sm:flex-none flex items-center justify-center gap-2 bg-stone-900 text-white hover:bg-stone-800 transition-all px-6 py-3 rounded-xl shadow-lg hover:shadow-xl active:scale-95"
                    >
                       <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4"/><polyline points="7 10 12 15 17 10"/><line x1="12" x2="12" y1="15" y2="3"/></svg>
                       <span className="font-bold">下载无水印高清图</span>
                    </button>
                    <button onClick={() => setResult(null)} className="flex-1 sm:flex-none flex items-center justify-center gap-2 bg-stone-100 text-stone-600 hover:text-stone-900 px-6 py-3 rounded-xl border border-stone-200 transition-all hover:bg-stone-200">
                      <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M3 12a9 9 0 1 0 9-9 9.75 9.75 0 0 0-6.74 2.74L3 8"/><path d="M3 3v5h5"/></svg>
                      <span className="font-bold">重新设计</span>
                    </button>
                  </div>
                </div>
              </div>
            )}

            {error && (
              <div className="bg-red-50 border border-red-200 text-red-800 px-6 py-4 rounded-xl flex items-center gap-3 animate-pulse">
                <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><circle cx="12" cy="12" r="10"/><line x1="12" x2="12" y1="8" y2="12"/><line x1="12" x2="12.01" y1="16" y2="16"/></svg>
                <p className="text-sm font-bold">{error}</p>
              </div>
            )}

            {/* 特色卡片 */}
            <div className="grid grid-cols-1 md:grid-cols-3 gap-6 pt-8">
              <div className="bg-white p-6 rounded-2xl border border-stone-200 shadow-sm">
                <div className="w-12 h-12 bg-stone-900 text-white rounded-xl flex items-center justify-center mb-4">
                  <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M12 22s8-4 8-10V5l-8-3-8 3v7c0 6 8 10 8 10"/></svg>
                </div>
                <h4 className="font-bold text-stone-900 mb-2">结构精准保护</h4>
                <p className="text-stone-600 text-sm leading-relaxed">AI 会精准识别毛坯房的轴线关系，确保装修方案完全贴合您的原始墙体和窗位。</p>
              </div>
              <div className="bg-white p-6 rounded-2xl border border-stone-200 shadow-sm">
                <div className="w-12 h-12 bg-stone-900 text-white rounded-xl flex items-center justify-center mb-4">
                  <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M17.5 19H9a7 7 0 1 1 6.71-9h1.79a4.5 4.5 0 1 1 0 9Z"/></svg>
                </div>
                <h4 className="font-bold text-stone-900 mb-2">全面覆盖毛坯</h4>
                <p className="text-stone-600 text-sm leading-relaxed">彻底告别水泥感。每个角落都会被高清纹理、真实光影和高档材质重新粉刷覆盖。</p>
              </div>
              <div className="bg-white p-6 rounded-2xl border border-stone-200 shadow-sm">
                <div className="w-12 h-12 bg-stone-900 text-white rounded-xl flex items-center justify-center mb-4">
                  <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="m12 3-1.912 5.813a2 2 0 0 1-1.275 1.275L3 12l5.813 1.912a2 2 0 0 1 1.275 1.275L12 21l1.912-5.813a2 2 0 0 1 1.275-1.275L21 12l-5.813-1.912a2 2 0 0 1-1.275-1.275L12 3Z"/></svg>
                </div>
                <h4 className="font-bold text-stone-900 mb-2">高清无水印</h4>
                <p className="text-stone-600 text-sm leading-relaxed">提供纯净的高分辨率结果图，无任何广告或水印，可直接用于您的家装规划。 </p>
              </div>
            </div>
          </div>

        </div>
      </main>

      <footer className="bg-white border-t border-stone-200 py-12">
        <div className="max-w-7xl mx-auto px-4 text-center">
          <div className="flex justify-center items-center gap-2 mb-4">
            <div className="w-8 h-8 bg-stone-800 flex items-center justify-center rounded-sm">
              <span className="text-white font-serif-sc text-sm">禅</span>
            </div>
            <span className="text-lg font-serif-sc font-bold tracking-tight">禅艺 AI 装修</span>
          </div>
          <p className="text-stone-500 text-sm">© 2024 禅艺空间视觉实验室。基于 Gemini 提供技术支持。已验证结构完整性。</p>
        </div>
      </footer>
    </div>
  );
};

export default App;
